const staticData = $getWorkflowStaticData('node');

const attempts = staticData.attempts ?? 0;
const newAttempts = attempts + 1;

if (newAttempts >= 3) {
    staticData.attempts = 0; // reset for next execution
    return [{ json: { ...$json, attempts: newAttempts, is_failed: 'yes' } }];
}

staticData.attempts = newAttempts;
return [{ json: { ...$json, attempts: newAttempts, is_failed: 'no' } }];

const output = $json.output || '';

const requiredKeywords = [
    ['Revenue', 'Projections de revenus', 'Revenus'],
    ['Cost', 'Structure des coûts', 'Coûts'],
    ['Funding', 'Financement'],
    ['Break', 'Seuil de rentabilité'],
];

const missingKeywords = requiredKeywords.filter(group =>
    !group.some(kw => output.toLowerCase().includes(kw.toLowerCase()))
);

return [{
    json: {
        ...$json,
        keywords_valid: missingKeywords.length === 0 ? 'true' : 'false',
        missing_keywords: missingKeywords.map(g => g[0]),
    }
}];

const output = $json.output || '';
const minLength = 400;
const length_valid = output.length >= minLength ? 'true' : 'false';

return [{
  json: {
    ...$json,
    length_valid: length_valid,
    actual_length: output.length,
  }
}];

const raw = $('AI Agent').item.json.output || '';

// ── Extract chart data block ──
const chartDataMatch = raw.match(/---CHART_DATA_START---([\s\S]*?)---CHART_DATA_END---/);
let chartData = null;
let narrativeText = raw;

if (chartDataMatch) {
    try {
        const rawJson = chartDataMatch[1].trim()
            .replace(/(\d)\s+(\d)/g, '$1$2')
            .replace(/(\d+(?:\+\d+)+)/g, (match) => eval(match));

        chartData = JSON.parse(rawJson);

        const inputJson = $('Build Prompt').item.json.input_json || {};

        // ── FIX 1: Auto-correct profit (profit must always = revenue - costs) ──
        if (chartData.revenue && chartData.costs && chartData.profit) {
            chartData.profit = chartData.revenue.map((r, i) => {
                const correct = Math.round(r - (chartData.costs[i] || 0));
                if (chartData.profit[i] !== correct) {
                    console.log(`Profit Y${i + 1} corrected: ${chartData.profit[i]} → ${correct}`);
                }
                return correct;
            });
        }

        // ── FIX 2: Verify AND auto-correct cost breakdowns to match total costs ──
        ['y1', 'y2', 'y3'].forEach((yr, i) => {
            const bd = chartData[`cost_breakdown_${yr}`];
            const totalCost = chartData.costs?.[i];

            if (bd && totalCost !== undefined) {
                const sum = (bd.development || 0) +
                            (bd.marketing   || 0) +
                            (bd.operations  || 0);
                const delta = Math.round(totalCost - sum);

                if (Math.abs(delta) > 1) {
                    const largest = Object.entries(bd).reduce(
                        (a, b) => (b[1] > a[1] ? b : a)
                    );
                    bd[largest[0]] = Math.round(bd[largest[0]] + delta);
                    console.log(
                        `Cost breakdown Y${i + 1} corrected: ` +
                        `sum was ${sum}, total is ${totalCost}, ` +
                        `added ${delta} to ${largest[0]} → now ${bd[largest[0]]}`
                    );
                }
            }
        });

        // ── FIX 3: Enforce burn rate floor on Y1 costs ──
        const monthlyBurn = parseFloat(String(inputJson.monthly_burn).replace(/[^0-9.]/g, ''));
        if (!isNaN(monthlyBurn) && chartData.costs?.[0] !== undefined) {
            const burnFloor = Math.round(monthlyBurn * 12);
            if (chartData.costs[0] < burnFloor) {
                console.log(
                    `WARNING: Y1 costs (${chartData.costs[0]}) are below the burn rate floor ` +
                    `($${monthlyBurn}/month × 12 = $${burnFloor}). ` +
                    `This is mathematically impossible — flagging as burn_rate_flag.`
                );
            }
        }

        // ── FIX 4: Restore user-provided revenue if model changed it ──
        const userRevenues = [
            parseFloat(String(inputJson.revenue_y1).replace(/[^0-9.]/g, '')),
            parseFloat(String(inputJson.revenue_y2).replace(/[^0-9.]/g, '')),
            parseFloat(String(inputJson.revenue_y3).replace(/[^0-9.]/g, '')),
        ];
        chartData.revenue.forEach((r, i) => {
            if (!isNaN(userRevenues[i]) && Math.abs(r - userRevenues[i]) > 1) {
                console.log(
                    `Revenue Y${i + 1} restored: model output ${r}, user input was ${userRevenues[i]}`
                );
                chartData.revenue[i] = userRevenues[i];
                chartData.profit[i] = Math.round(userRevenues[i] - (chartData.costs[i] || 0));
            }
        });

        // ── FIX 5: Auto-correct decimal growth rate (0.15 → 15) ──
        if (chartData.monthly_growth_rate !== undefined && chartData.monthly_growth_rate < 1) {
            const corrected = Math.round(chartData.monthly_growth_rate * 100 * 10) / 10;
            console.log(`Growth rate corrected: ${chartData.monthly_growth_rate} → ${corrected}%`);
            chartData.monthly_growth_rate = corrected;
        }

        // ── FIX 6: ARPU sanity check ──
        if (chartData.arpu && chartData.arpu > 2000) {
            console.log(
                `WARNING: ARPU of ${chartData.arpu} exceeds $2,000/month. ` +
                `Verify against pricing tiers in Strategy context.`
            );
        }

        // ── FIX 7: All-loss flag ──
        if (chartData.profit && chartData.profit.every(p => p < 0)) {
            console.log('WARNING: All three years show a loss. Check narrative for Adjusted Scenario.');
        }

        narrativeText = raw
            .replace(/---CHART_DATA_START---[\s\S]*?---CHART_DATA_END---/, '')
            .replace(/###\s*PART\s*[12]\s*[—-]\s*[\w\s]+/gi, '')
            .trim();

    } catch (e) {
        chartData = null;
        console.log('Chart parse error:', e.message);
    }
}

// ── Extract MEMORY_SUMMARY ──
let memMatch = narrativeText.match(
    /(?:===|---|\*\*|)\s*MEMORY_SUMMARY\s*(?:===|---|\*\*|)[^\n]*\n([\s\S]*?)$/i
);
const memory_summary = memMatch ? memMatch[1].trim() : '';

// ── Clean narrative ──
let cleanNarrative = narrativeText
    .replace(/(?:===|---|\*\*|)\s*MEMORY_SUMMARY\s*[\s\S]*$/i, '')
    .trim();
cleanNarrative = cleanNarrative.replace(/===\s*[^=]*?\s*===/g, '').trim();
cleanNarrative = cleanNarrative.replace(/===\s*[^=]*?\s*===/g, '').trim();

// ── Parse MEMORY_SUMMARY into structured key-value object ──
const memoryObject = {};
if (memory_summary) {
    memory_summary.split('\n').forEach(line => {
        const colonIdx = line.indexOf(':');
        if (colonIdx !== -1) {
            const key = line.slice(0, colonIdx).trim()
                .toLowerCase()
                .replace(/\s+/g, '_');
            const value = line.slice(colonIdx + 1).trim();
            if (key && value) memoryObject[key] = value;
        }
    });
}

// ── Token estimation ──
const promptText    = $('Build Prompt').item.json.prompt || '';
const tokens_input  = Math.round(promptText.length / 4);
const tokens_output = Math.round(raw.length / 4);
const tokens_total  = tokens_input + tokens_output;

const buildData = $('Build Prompt').item.json;
const inputJson = $('Build Prompt').item.json.input_json || {};
const monthlyBurnFinal = parseFloat(String(inputJson.monthly_burn).replace(/[^0-9.]/g, ''));
const burnFloorFinal   = !isNaN(monthlyBurnFinal) ? Math.round(monthlyBurnFinal * 12) : null;

return [{
    json: {
        ...buildData,
        output: cleanNarrative,
        chart_data: chartData ? JSON.stringify(chartData) : null,
        memory_summary,
        memory_object: memoryObject,
        all_loss_flag:    chartData?.profit?.every(p => p < 0) ?? false,
        burn_rate_flag:   burnFloorFinal !== null && chartData?.costs?.[0] !== undefined
                            ? chartData.costs[0] < burnFloorFinal
                            : false,
        tokens_input,
        tokens_output,
        tokens_total,
    }
}];
